#include <stdio.h>
#include <stdlib.h>

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        int** matrix = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            matrix[i] = (int*)malloc(M * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                scanf("%d", &matrix[i][j]);
            }
        }
        int** result = (int**)malloc(N * sizeof(int*));
        for (int i = 0; i < N; i++) {
            result[i] = (int*)malloc(M * sizeof(int));
        }
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (matrix[i][j] == -1) {
                    if (i == 0 && j == 0) {
                        result[i][j] = 1;
                    } else if (i == 0) {
                        result[i][j] = result[i][j-1];
                    } else if (j == 0) {
                        result[i][j] = result[i-1][j];
                    } else {
                        result[i][j] = (result[i-1][j] > result[i][j-1] ? result[i-1][j] : result[i][j-1]) + 1;
                    }
                } else {
                    result[i][j] = matrix[i][j];
                }
            }
        }
        int valid = 1;
        for (int i = 0; i < N; i++) {
            for (int j = 0; j < M; j++) {
                if (i > 0 && result[i][j] < result[i-1][j]) {
                    valid = 0;
                    break;
                }
                if (j > 0 && result[i][j] < result[i][j-1]) {
                    valid = 0;
                    break;
                }
            }
            if (!valid) break;
        }
        if (!valid) {
            printf("-1\n");
        } else {
            for (int i = 0; i < N; i++) {
                for (int j = 0; j < M; j++) {
                    printf("%d ", result[i][j]);
                }
                printf("\n");
            }
        }
        for (int i = 0; i < N; i++) {
            free(matrix[i]);
            free(result[i]);
        }
        free(matrix);
        free(result);
    }
    return 0;
}

